-- DND2024: описания предысторий из next.dnd.su (текст из itemprop="description")
-- Источник: https://next.dnd.su/backgrounds/

UPDATE rules.default_2024_background
SET description = 'Вы посвятили себя служению в храме, среди городских улиц или в уединении священной рощи. Там вы совершали обряды в честь бога или пантеона. Вы изучали религию под началом священника. Благодаря его наставлениям и вашей собственной преданности вы научились направлять капельку божественной силы на служение своему месту поклонения и людям, которые там молились.'
WHERE code = 'ACOLYTE';

UPDATE rules.default_2024_background
SET description = 'Вы начали мыть полы и прилавки в мастерской ремесленника за несколько медяков в день, как только окрепли настолько, что могли носить ведро. Когда вы подросли и стали подмастерьем, вы научились как самостоятельно работать азы своего ремесла, так и тому, как умилостивить требовательного подчас покупателя. Ваша профессия также наделила вас внимательным к деталям взглядом.'
WHERE code = 'ARTISAN';

UPDATE rules.default_2024_background
SET description = 'Совсем мало времени прошло после того, как вы стали достаточно взрослы, чтобы заказывать эль — а у вас уже появилось любимое место в каждой таверне в окрестностях десяти миль. От трактира вечером к колодцам поутру, вы научились наживаться на несчастных, ищущих утешивших бы их лжи — возможно, фальшивого зелья или поддельных записей о родословной.'
WHERE code = 'CHARLATAN';

UPDATE rules.default_2024_background
SET description = 'Вы зарабатывали на жизнь в тёмных переулках, срезая кошельки и проникая в лавки. Возможно, вы были частью небольшой банды единомышленников-правонарушителей, присматривавшей друг за другом. А может быть, вы были одиноким волком, не желавшим иметь дел с местной гильдией воров и более грозными нарушителями закона.'
WHERE code = 'CRIMINAL';

UPDATE rules.default_2024_background
SET description = 'Вы провели большую часть своей юности следуя за бродячими ярмарками и карнавалами, иногда работая на музыкантов и акробатов в обмен на уроки. Возможно, вы научились ходить по канату, играть на лютне в особом стиле или декламировать стихи с безупречной дикцией. По сей день вы наслаждаетесь аплодисментами и стремитесь на сцену.'
WHERE code = 'ENTERTAINER';

UPDATE rules.default_2024_background
SET description = 'Вы выросли в близости с землёй. За годы ухода за животными и работы в поле вы выработали терпение и крепкое здоровье. Вы высоко цените щедрость природы — и испытываете разумное уважение к её гневу.'
WHERE code = 'FARMER';

UPDATE rules.default_2024_background
SET description = 'Когда вы только вспоминаете бесчисленные часы, проведённые на посту в башне, у вас начинают ныть ноги. Вы были обучены смотреть одним глазом за стены, высматривая мародеров из близлежащего леса, а другим глазом в поселение, следя за щипачами и смутьянами.'
WHERE code = 'GUARD';

UPDATE rules.default_2024_background
SET description = 'Вы вошли в возраст под открытым небом, вдали от обжитых земель. Домом вам было то место, где вы решили расстелить свой спальник. В дикой природе есть чудеса — странные чудовища, девственные леса и ручьи, заросшие руины огромных залов, по которым когда-то ходили великаны — и исследуя их, вы научились постоять за себя. Временами вам доводилось быть проводником дружественным жрецам природы, которые обучали вас основам магии дикой природы.'
WHERE code = 'GUIDE';

UPDATE rules.default_2024_background
SET description = 'Вы провели свои ранние годы в одиночестве, в хижине или монастыре, далеко за пределами ближайшего поселения. В те дни единственными вашими спутниками были лесные обитатели и те, кто время от времени навещал вас, принося новости о внешнем мире и припасы. В уединении вы провели много часов, размышляя о тайнах сотворения мира.'
WHERE code = 'HERMIT';

UPDATE rules.default_2024_background
SET description = 'Вы были учеником торговца, хозяина каравана или лавочника, и так изучили основы коммерции. Вы много путешествовали, зарабатывая на жизнь перепродажей сырья, необходимого ремесленникам, или готовых работ мастеров. Возможно, вы перевозили товары из одного места в другое (на корабле, фургоне или караванами) или покупали их у странствующих торговцев и продавали в своем собственном магазине.'
WHERE code = 'MERCHANT';

UPDATE rules.default_2024_background
SET description = 'Вы выросли в замке, окруженные богатством, властью и привилегиями. Ваша семья, из мелких аристократов, позаботилась о том, чтобы вы получили первоклассное образование; часть его вы ценили, часть вызывала у вас негодование. Ваше пребывание в замке, особенно долгие часы наблюдений за своей семьей при дворе, также многому научили вас в вопросах лидерства.'
WHERE code = 'NOBLE';

UPDATE rules.default_2024_background
SET description = 'Вы провели свои юные годы, путешествуя между поместьями и монастырями, выполняя для них работу и оказывая услуги в обмен на доступ к их библиотекам. Вы провели много долгих вечеров за книгами и свитками; вы изучали знания о мультивселенной, и даже основы магии — и ваш разум жаждет большего.'
WHERE code = 'SAGE';

UPDATE rules.default_2024_background
SET description = 'Вы жили на морских просторах, ветер дул вам в спину, и палуба покачивалась под вашими ногами. Вы сидели в большем количестве портовых баров, чем можете припомнить, проходили через сильные шторма и болтали с подводными обитателями.'
WHERE code = 'SAILOR';

UPDATE rules.default_2024_background
SET description = 'Годы вашего становления прошли в скриптории, в государственном учреждении или в монастыре, посвященном сохранению знаний. Там вы научились писать чётким почерком, создавая тонко написанные тексты. Возможно, вы переписывали правительственные документы или копировали рукописные тома. Возможно, у вас есть некоторые навыки в написании поэзии, повествовании или научных исследованиях. Прежде всего вы уделяете внимание деталям, что помогает вам избегать ошибок в документах, которые вы копируете и создаёте.'
WHERE code = 'SCRIBE';

UPDATE rules.default_2024_background
SET description = 'Вы начали готовиться к войне, как только достигли зрелости, и вы почти не помните свою жизнь до того, как взяли в руки оружие. Битва у вас в крови. Иногда вы ловите себя на том, что бездумно выполняете первые изученные вами боевые упражнения. Теперь вы применяете это обучение на поле боя, защищая мир — войной.'
WHERE code = 'SOLDIER';

UPDATE rules.default_2024_background
SET description = 'Вы выросли на улицах в окружении таких же злосчастных отбросов общества; с кем-то из них вы дружили, с кем-то соперничали. Вы спали, где придётся, перебиваясь подработками. Временами, когда голод становился невыносимым, вы прибегали к воровству. Тем не менее, вы никогда не теряли своей гордости и не оставляли надежды. Судьба ещё может вам улыбнуться.'
WHERE code = 'WAYFARER';
